import React, { useState } from "react";
import axios from "axios";

const API_BASE = "http://localhost:8000"; // Backend API

function App() {
  const [commitMessage, setCommitMessage] = useState("");
  const [files, setFiles] = useState("");
  const [linesChanged, setLinesChanged] = useState(0);
  const [prevBugs, setPrevBugs] = useState(0);
  const [testCoverage, setTestCoverage] = useState(100);

  const [complianceResult, setComplianceResult] = useState(null);
  const [riskResult, setRiskResult] = useState(null);

  const handleCheck = async () => {
    try {
      // Compliance Check
      const complianceRes = await axios.post(`${API_BASE}/api/compliance-check`, {
        commit_message: commitMessage,
        files: files.split(",").map(f => f.trim()).filter(f => f),
      });
      setComplianceResult(complianceRes.data);

      // Risk Predictor
      const riskRes = await axios.post(`${API_BASE}/api/risk-score`, {
        commit_message: commitMessage,
        files: files.split(",").map(f => f.trim()).filter(f => f),
        lines_changed: parseInt(linesChanged, 10),
        prev_bugs: parseInt(prevBugs, 10),
        test_coverage: parseInt(testCoverage, 10),
      });
      setRiskResult(riskRes.data);

    } catch (err) {
      console.error("Error:", err);
      alert("Error connecting to backend. Is it running?");
    }
  };

  return (
    <div style={{ padding: "2rem", fontFamily: "Arial" }}>
      <h1>🚨 Sentinel Dashboard</h1>

      <div style={{ marginBottom: "1rem" }}>
        <label>Commit Message:</label><br />
        <input
          type="text"
          value={commitMessage}
          onChange={(e) => setCommitMessage(e.target.value)}
          style={{ width: "400px" }}
        />
      </div>

      <div style={{ marginBottom: "1rem" }}>
        <label>Files Changed (comma separated):</label><br />
        <input
          type="text"
          value={files}
          onChange={(e) => setFiles(e.target.value)}
          style={{ width: "400px" }}
        />
      </div>

      <div style={{ marginBottom: "1rem" }}>
        <label>Lines Changed:</label><br />
        <input
          type="number"
          value={linesChanged}
          onChange={(e) => setLinesChanged(e.target.value)}
        />
      </div>

      <div style={{ marginBottom: "1rem" }}>
        <label>Previous Bugs:</label><br />
        <input
          type="number"
          value={prevBugs}
          onChange={(e) => setPrevBugs(e.target.value)}
        />
      </div>

      <div style={{ marginBottom: "1rem" }}>
        <label>Test Coverage %:</label><br />
        <input
          type="number"
          value={testCoverage}
          onChange={(e) => setTestCoverage(e.target.value)}
        />
      </div>

      <button onClick={handleCheck} style={{ padding: "10px 20px", fontSize: "16px" }}>
        Run Sentinel Check
      </button>

      {complianceResult && (
        <div style={{ marginTop: "2rem", border: "1px solid gray", padding: "1rem" }}>
          <h2>Compliance Result</h2>
          <p><b>{complianceResult.title}</b></p>
          <p>{complianceResult.message}</p>
        </div>
      )}

      {riskResult && (
        <div style={{ marginTop: "2rem", border: "1px solid gray", padding: "1rem" }}>
          <h2>Risk Prediction</h2>
          <p><b>Risk Score:</b> {riskResult.risk_score}%</p>
          <pre>{JSON.stringify(riskResult.factors, null, 2)}</pre>
          <p>{riskResult.message}</p>
        </div>
      )}
    </div>
  );
}

export default App;
